import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Create a CSVFormat instance using the default constructor via reflection
        // because the constructor is private
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Ensure nullString field is null
        setNullString(csvFormat, null);
        assertFalse(csvFormat.isNullStringSet());
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Set nullString field to a non-null value
        setNullString(csvFormat, "NULL");
        assertTrue(csvFormat.isNullStringSet());
    }

    private void setNullString(CSVFormat format, String value) throws Exception {
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, value);
    }
}
